1	#!/usr/bin/env node
2	/**
3	 * CLI entry point for the generic LLM instrument runner.
4	 *
5	 * Usage:
6	 *   instrument-runner --instrument-name <name> [--instrument-version <v>] \
7	 *     --param key=value --output-dir <path> [--dry-run]
8	 *
9	 *   instrument-runner --instrument <path-to-version-dir> \
10	 *     --param key=value --output-dir <path> [--dry-run]
11	 *
12	 * Instrument resolution (in priority order):
13	 *   1. --instrument <path>    Explicit path to a versioned instrument directory
14	 *   2. --instrument-name + --instrument-version    Resolves under instrument root
15	 *   3. --instrument-name only    Auto-selects version if exactly one exists
16	 *
17	 * The instrument root defaults to experiments/instruments/ relative to cwd,
18	 * overridable via --instrument-root.
19	 */
20	
21	import { mkdtempSync } from 'node:fs';
22	import { resolve } from 'node:path';
23	import { tmpdir } from 'node:os';
24	import { parseArgs } from 'node:util';
25	import { resolveInstrumentDir } from './resolve.ts';
26	import { loadConfig, validateParams } from './config.ts';
27	import { runSetup, runExtractors } from './extract.ts';
28	import { assemblePrompts } from './template.ts';
29	import { executeRuns } from './execute.ts';
30	import { parseRun } from './parse.ts';
31	import { aggregate } from './aggregate.ts';
32	import { writeArtifact, writeContext, writeRunTranscripts, aggregateCost } from './artifact.ts';
33	import type { ResolvedParams, ParsedRun } from './types.ts';
34	
35	// ── Parse CLI arguments ─────────────────────────────────────
36	
37	function parseCliArgs(): {
38	  instrumentDir: string;
39	  params: ResolvedParams;
40	  outputDir: string;
41	  dryRun: boolean;
42	} {
43	  const { values } = parseArgs({
44	    allowPositionals: false,
45	    options: {
46	      instrument: { type: 'string' },
47	      'instrument-root': { type: 'string' },
48	      'instrument-name': { type: 'string' },
49	      'instrument-version': { type: 'string' },
50	      param: { type: 'string', multiple: true },
51	      'output-dir': { type: 'string' },
52	      'dry-run': { type: 'boolean', default: false },
53	      help: { type: 'boolean', default: false },
54	    },
55	  });
56	
57	  if (values.help) {
58	    console.log(`
59	Usage:
60	  instrument-runner --instrument-name <name> [options]
61	  instrument-runner --instrument <path> [options]
62	
63	Instrument resolution:
64	  --instrument <dir>          Explicit path to versioned instrument directory
65	  --instrument-name <name>    Instrument name (resolved under instrument root)
66	  --instrument-version <v>    Version to use (required if multiple exist)
67	  --instrument-root <dir>     Root directory (default: experiments/instruments)
68	
69	Options:
70	  --param key=value    Parameter to pass to extractors (repeatable)
71	  --output-dir <dir>   Where to write artifacts (default: ./output)
72	  --dry-run            Print plan without executing LLM calls
73	  --help               Show this help
74	`);
75	    process.exit(0);
76	  }
77	
78	  // Resolve instrument directory
79	  const instrumentDir = resolveInstrumentDir({
80	    instrument: values.instrument,
81	    instrumentRoot: values['instrument-root'],
82	    instrumentName: values['instrument-name'],
83	    instrumentVersion: values['instrument-version'],
84	  });
85	
86	  // Parse --param key=value pairs
87	  const params: ResolvedParams = {};
88	  for (const p of values.param ?? []) {
89	    const eq = p.indexOf('=');
90	    if (eq === -1) {
91	      console.error(`Error: --param must be key=value, got: ${p}`);
92	      process.exit(1);
93	    }
94	    params[p.slice(0, eq)] = p.slice(eq + 1);
95	  }
96	
97	  return {
98	    instrumentDir,
99	    params,
100	    outputDir: resolve(values['output-dir'] ?? './output'),
101	    dryRun: values['dry-run'] ?? false,
102	  };
103	}
104	
105	// ── Main ────────────────────────────────────────────────────
106	
107	async function main(): Promise<void> {
108	  const { instrumentDir, params, outputDir, dryRun } = parseCliArgs();
109	
110	  // 1. Configure
111	  console.log(`═══ Instrument Runner ═══`);
112	  const config = loadConfig(instrumentDir);
113	  console.log(`  Instrument: ${config.name} ${config.version}`);
114	  console.log(`  Model:      ${config.execution.model}`);
115	  console.log(`  Runs:       ${config.execution.runs}`);
116	  console.log(`  Output:     ${outputDir}`);
117	  console.log('');
118	
119	  validateParams(config, params);
120	
121	  // 2. Extract
122	  console.log('── Extracting inputs ──');
123	  const contextDir = mkdtempSync(`${tmpdir()}/instrument-ctx-`);
124	
125	  runSetup(config, instrumentDir, params, contextDir);
126	
127	  const inputs = runExtractors(config, instrumentDir, params, contextDir);
128	  for (const [name, value] of Object.entries(inputs)) {
129	    const lines = value.split('\n').length;
130	    console.log(`  ${name}: ${lines} lines`);
131	  }
132	  console.log('');
133	
134	  // 3. Assemble prompts
135	  const { systemPrompt, userMessage } = assemblePrompts(instrumentDir, config.prompts, inputs);
136	  console.log(`  System prompt: ${systemPrompt.split('\n').length} lines`);
137	  console.log(`  User message:  ${userMessage.split('\n').length} lines`);
138	  console.log('');
139	
140	  // Save context for reproducibility (before execution, in case it fails)
141	  writeContext(outputDir, config, systemPrompt, userMessage, inputs);
142	  console.log(`  Context saved to: ${outputDir}/instruments/${config.name}/context/`);
143	
144	  if (dryRun) {
145	    console.log('');
146	    console.log('── DRY RUN ──');
147	    console.log(`Would execute ${config.execution.runs} runs`);
148	    console.log(`System prompt: ${systemPrompt.split('\n').length} lines`);
149	    console.log(`User message: ${userMessage.split('\n').length} lines`);
150	    process.exit(0);
151	  }
152	
153	  // 4. Execute
154	  console.log('');
155	  console.log(`── Running ${config.execution.runs} independent reviews in parallel ──`);
156	
157	  const outcomes = await executeRuns(config.execution, systemPrompt, userMessage);
158	
159	  const successful = outcomes.filter((o) => o.success);
160	  const failed = outcomes.filter((o) => !o.success);
161	
162	  for (const o of outcomes) {
163	    const costStr = o.usage ? ` ($${o.usage.cost_usd.toFixed(4)})` : '';
164	    console.log(`  ${o.success ? '✓' : '✗'} Run ${o.index + 1}${costStr}${o.error ? ` — ${o.error.split('\n')[0]}` : ''}`);
165	  }
166	
167	  if (successful.length < config.execution.min_successful_runs) {
168	    console.error(
169	      `\nError: only ${successful.length} runs succeeded (need at least ${config.execution.min_successful_runs})`,
170	    );
171	    process.exit(3);
172	  }
173	
174	  if (failed.length > 0) {
175	    console.log(`\n  Warning: ${failed.length} of ${config.execution.runs} runs failed.`);
176	  }
177	
178	  // 5. Write per-run transcripts (before parsing, so we capture even unparseable runs)
179	  writeRunTranscripts(outputDir, config, outcomes);
180	  console.log(`  Transcripts saved to: ${outputDir}/instruments/${config.name}/runs/`);
181	
182	  // 6. Parse
183	  console.log('');
184	  console.log('── Parsing responses ──');
185	
186	  const parsedRuns: ParsedRun[] = [];
187	  for (const outcome of successful) {
188	    const parsed = parseRun(outcome.response, config.output);
189	    if (parsed) {
190	      // Attach usage data to parsed run
191	      if (outcome.usage) {
192	        parsed.usage = outcome.usage;
193	      }
194	      parsedRuns.push(parsed);
195	      console.log(`  ✓ Run ${outcome.index + 1}: composite ${parsed.composite}`);
196	    } else {
197	      console.log(`  ✗ Run ${outcome.index + 1}: could not parse valid scores`);
198	    }
199	  }
200	
201	  if (parsedRuns.length < config.execution.min_successful_runs) {
202	    console.error(
203	      `\nError: only ${parsedRuns.length} runs produced parseable scores (need at least ${config.execution.min_successful_runs})`,
204	    );
205	    process.exit(4);
206	  }
207	
208	  // 7. Aggregate
209	  const agg = aggregate(parsedRuns, config.output.dimensions);
210	  const cost = aggregateCost(outcomes);
211	
212	  // 8. Write artifact
213	  const result = {
214	    instrument: { name: config.name, version: config.version },
215	    params,
216	    reviewed_at: new Date().toISOString(),
217	    aggregate: agg,
218	    cost,
219	    runs: parsedRuns,
220	  };
221	
222	  const artifactPath = writeArtifact(outputDir, config, result);
223	
224	  // Summary
225	  console.log('');
226	  console.log('═══ Review Complete ═══');
227	  console.log('');
228	  console.log(`  Composite:  ${agg.composite} (sd: ${agg.composite_sd})`);
229	  console.log('  Dimensions:');
230	  for (const [name, stats] of Object.entries(agg.dimensions)) {
231	    console.log(`    ${name.padEnd(25)} ${stats.mean} (sd: ${stats.sd})`);
232	  }
233	  if (cost) {
234	    console.log('');
235	    console.log(`  Cost:       $${cost.total_cost_usd.toFixed(4)} (${cost.model})`);
236	    console.log(`  Tokens:     ${cost.total_input_tokens + cost.total_cache_creation_tokens + cost.total_cache_read_tokens} in / ${cost.total_output_tokens} out`);
237	    console.log(`  Duration:   ${(cost.total_duration_ms / 1000).toFixed(1)}s`);
238	  }
239	  console.log('');
240	  console.log(`  Artifact: ${artifactPath}`);
241	
242	  if (agg.composite_sd > 0.5) {
243	    console.log('');
244	    console.log(`  ⚠ High composite variance (sd: ${agg.composite_sd}).`);
245	    console.log('    Consider increasing runs for this commission.');
246	  }
247	}
248	
