1	/**
2	 * Execute parallel LLM instrument runs via `claude --print`.
3	 *
4	 * Each run is independent: separate API call, independent sampling.
5	 * The runner spawns N parallel processes with full isolation (no tools,
6	 * no project config, sandboxed working directory).
7	 *
8	 * Uses `--output-format json` to capture the full response envelope
9	 * including token usage, cost, session ID, and duration alongside
10	 * the LLM's text output.
11	 */
12	
13	import { execFile } from 'node:child_process';
14	import { mkdtempSync } from 'node:fs';
15	import { join } from 'node:path';
16	import { tmpdir } from 'node:os';
17	import type { ExecutionConfig, RunUsage } from './types.ts';
18	
19	/** Maximum time per LLM run (5 minutes) */
20	const RUN_TIMEOUT_MS = 5 * 60 * 1000;
21	
22	export interface RunOutcome {
23	  index: number;
24	  success: boolean;
25	  response: string;
26	  error?: string;
27	  /** Full JSON envelope from claude --print --output-format json */
28	  rawJson?: Record<string, unknown>;
29	  /** Extracted usage/cost data */
30	  usage?: RunUsage;
31	}
32	
33	/**
34	 * Parse the JSON envelope from `claude --print --output-format json`.
35	 *
36	 * Extracts the text result and usage/cost metadata.
37	 */
38	function parseJsonEnvelope(stdout: string): {
39	  text: string;
40	  rawJson: Record<string, unknown>;
41	  usage: RunUsage;
42	} {
43	  const envelope = JSON.parse(stdout) as Record<string, unknown>;
44	  const text = String(envelope.result ?? '');
45	
46	  // Extract usage data from the envelope
47	  const usageBlock = (envelope.usage ?? {}) as Record<string, unknown>;
48	  const modelUsage = (envelope.modelUsage ?? {}) as Record<string, Record<string, unknown>>;
49	  const modelNames = Object.keys(modelUsage);
50	
51	  const usage: RunUsage = {
52	    input_tokens: Number(usageBlock.input_tokens ?? 0),
53	    output_tokens: Number(usageBlock.output_tokens ?? 0),
54	    cache_creation_input_tokens: Number(usageBlock.cache_creation_input_tokens ?? 0),
55	    cache_read_input_tokens: Number(usageBlock.cache_read_input_tokens ?? 0),
56	    cost_usd: Number(envelope.total_cost_usd ?? 0),
57	    duration_ms: Number(envelope.duration_ms ?? 0),
58	    session_id: String(envelope.session_id ?? ''),
59	    model: modelNames[0] ?? 'unknown',
60	  };
61	
62	  return { text, rawJson: envelope, usage };
63	}
64	
65	/**
66	 * Execute a single instrument run.
67	 *
68	 * Pipes the user message via stdin to avoid OS argument length limits.
69	 * The process runs in an empty tmpdir with all tools disabled.
70	 */
71	function executeRun(
72	  config: ExecutionConfig,
73	  systemPrompt: string,
74	  userMessage: string,
75	  sandboxDir: string,
76	  index: number,
77	): Promise<RunOutcome> {
78	  return new Promise((resolve) => {
79	    const args = [
80	      '--print',
81	      '--model', config.model,
82	      '--output-format', 'json',
83	      '--max-turns', String(config.max_turns),
84	      '--tools', '',
85	      '--disallowed-tools', 'Bash,Read,Write,Edit,Glob,Grep',
86	      '--setting-sources', 'user',
87	      '--system-prompt', systemPrompt,
88	    ];
89	
90	    const proc = execFile('claude', args, {
91	      cwd: sandboxDir,
92	      timeout: RUN_TIMEOUT_MS,
93	      maxBuffer: 10 * 1024 * 1024,
94	      env: {
95	        PATH: process.env.PATH ?? '/usr/local/bin:/usr/bin:/bin',
96	        HOME: process.env.HOME ?? '/tmp',
97	      },
98	    }, (err, stdout, stderr) => {
99	      if (err) {
100	        resolve({
101	          index,
102	          success: false,
103	          response: '',
104	          error: err.message + (stderr ? `\n${stderr}` : ''),
105	        });
106	        return;
107	      }
108	
109	      try {
110	        const { text, rawJson, usage } = parseJsonEnvelope(stdout);
111	        resolve({ index, success: true, response: text, rawJson, usage });
112	      } catch (parseErr) {
113	        // JSON parse failed — fall back to treating stdout as raw text
114	        // (shouldn't happen, but defensive)
115	        resolve({
116	          index,
117	          success: true,
118	          response: stdout,
119	          error: `JSON envelope parse failed: ${parseErr}`,
120	        });
121	      }
122	    });
123	
124	    // Pipe user message via stdin
125	    if (proc.stdin) {
