1	/**
2	 * Write structured YAML artifacts from instrument results.
3	 *
4	 * Produces three outputs:
5	 *   1. The result artifact (scores, aggregate, cost, per-run detail)
6	 *   2. The context archive (assembled prompts for reproducibility)
7	 *   3. Per-run transcript JSON (full LLM response envelopes for forensics)
8	 */
9	
10	import { mkdirSync, writeFileSync } from 'node:fs';
11	import { join } from 'node:path';
12	import yaml from 'js-yaml';
13	import type { InstrumentConfig, InstrumentResult, AggregateCost, ResolvedParams } from './types.ts';
14	import type { RunOutcome } from './execute.ts';
15	
16	/**
17	 * Write the result artifact to the output directory.
18	 */
19	export function writeArtifact(
20	  outputDir: string,
21	  config: InstrumentConfig,
22	  result: InstrumentResult,
23	): string {
24	  const instrumentDir = join(outputDir, 'instruments', config.name);
25	  mkdirSync(instrumentDir, { recursive: true });
26	
27	  // Build the artifact document
28	  const doc: Record<string, unknown> = {
29	    instrument: {
30	      name: config.name,
31	      version: config.version,
32	    },
33	    reviewed_at: result.reviewed_at,
34	    params: result.params,
35	
36	    aggregate: {
37	      composite: result.aggregate.composite,
38	      composite_sd: result.aggregate.composite_sd,
39	      n: result.aggregate.n,
40	      dimensions: result.aggregate.dimensions,
41	    },
42	  };
43	
44	  if (result.aggregate.high_variance.length > 0) {
45	    (doc.aggregate as Record<string, unknown>).high_variance = result.aggregate.high_variance;
46	  }
47	
48	  // Cost summary (when available)
49	  if (result.cost) {
50	    doc.cost = result.cost;
51	  }
52	
53	  // Per-run detail
54	  doc.runs = result.runs.map((run, i) => {
55	    const runDoc: Record<string, unknown> = {
56	      run: i + 1,
57	      ...run.dimensions,
58	      composite: run.composite,
59	      ...run.qualitative,
60	    };
61	    if (run.usage) {
62	      runDoc.cost_usd = run.usage.cost_usd;
63	      runDoc.duration_ms = run.usage.duration_ms;
64	    }
65	    return runDoc;
66	  });
67	
68	  const artifactPath = join(instrumentDir, 'result.yaml');
69	  const header = [
70	    `# Instrument: ${config.name} ${config.version}`,
71	    `# Commission: ${result.params.commission ?? 'unknown'}`,
72	    `# Generated: ${result.reviewed_at}`,
73	    `# Runs: ${result.aggregate.n} successful of ${config.execution.runs} attempted`,
74	    '',
75	  ].join('\n');
76	
77	  writeFileSync(artifactPath, header + yaml.dump(doc, { lineWidth: 120, sortKeys: false }));
78	  return artifactPath;
79	}
80	
81	/**
82	 * Write per-run transcript JSON files for forensic analysis.
83	 *
84	 * Each file contains the full `claude --print --output-format json` envelope,
85	 * preserving the raw LLM response, token usage, cost, and session ID.
86	 */
87	export function writeRunTranscripts(
88	  outputDir: string,
89	  config: InstrumentConfig,
90	  outcomes: RunOutcome[],
91	): void {
92	  const runsDir = join(outputDir, 'instruments', config.name, 'runs');
93	  mkdirSync(runsDir, { recursive: true });
94	
95	  for (const outcome of outcomes) {
96	    const data = outcome.rawJson ?? {
97	      // Fallback when JSON envelope wasn't captured
98	      response_text: outcome.response,
99	      error: outcome.error,
100	      success: outcome.success,
101	    };
102	    writeFileSync(
103	      join(runsDir, `run-${outcome.index + 1}.json`),
104	      JSON.stringify(data, null, 2) + '\n',
105	    );
106	  }
107	}
108	
109	/**
110	 * Save the assembled prompts and extraction context for reproducibility.
111	 */
112	export function writeContext(
113	  outputDir: string,
114	  config: InstrumentConfig,
115	  systemPrompt: string,
116	  userMessage: string,
117	  extractedInputs: Record<string, string>,
118	): void {
119	  // Output to instruments/{name}/context/
120	  const contextDir = join(outputDir, 'instruments', config.name, 'context');
121	  mkdirSync(contextDir, { recursive: true });
122	
123	  writeFileSync(join(contextDir, 'system-prompt.md'), systemPrompt);
124	  writeFileSync(join(contextDir, 'user-message.md'), userMessage);
125	
126	  // Save each extracted input separately
127	  for (const [name, value] of Object.entries(extractedInputs)) {
128	    if (value) {
129	      writeFileSync(join(contextDir, `input-${name.toLowerCase()}.txt`), value);
130	    }
131	  }
132	}
133	
134	/**
135	 * Aggregate cost data across successful runs.
136	 */
137	export function aggregateCost(outcomes: RunOutcome[]): AggregateCost | undefined {
138	  const withUsage = outcomes.filter((o) => o.success && o.usage);
139	  if (withUsage.length === 0) return undefined;
140	
141	  return {
142	    total_cost_usd: round(withUsage.reduce((sum, o) => sum + (o.usage?.cost_usd ?? 0), 0), 6),
143	    total_input_tokens: withUsage.reduce((sum, o) => sum + (o.usage?.input_tokens ?? 0), 0),
144	    total_output_tokens: withUsage.reduce((sum, o) => sum + (o.usage?.output_tokens ?? 0), 0),
145	    total_cache_creation_tokens: withUsage.reduce((sum, o) => sum + (o.usage?.cache_creation_input_tokens ?? 0), 0),
146	    total_cache_read_tokens: withUsage.reduce((sum, o) => sum + (o.usage?.cache_read_input_tokens ?? 0), 0),
147	    total_duration_ms: withUsage.reduce((sum, o) => sum + (o.usage?.duration_ms ?? 0), 0),
148	    model: withUsage[0]?.usage?.model ?? 'unknown',
149	  };
150	}
151	
152	function round(n: number, decimals: number): number {
153	  const factor = 10 ** decimals;
154	  return Math.round(n * factor) / factor;
155	}
156

