1	/**
2	 * Parse and validate instrument.yaml configuration.
3	 */
4	
5	import { readFileSync } from 'node:fs';
6	import { join } from 'node:path';
7	import yaml from 'js-yaml';
8	import type {
9	  InstrumentConfig,
10	  ExecutionConfig,
11	  ParameterDef,
12	  InputDef,
13	  PromptPaths,
14	  OutputSchema,
15	  DimensionDef,
16	  QualitativeDef,
17	  CompositeDef,
18	  ResolvedParams,
19	} from './types.ts';
20	
